module RefModule(A, B, Z, OVF);input [1:0] A;
input [1:0] B;
output reg [1:0] Z; // Change output Z to reg type
output OVF;

wire [2:0] sum;
  wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign sum = {_n01, _n02, _n03, _n04};
assign OVF = (sum > 3);

always @* begin
    if (sum > 3)
        Z = 2'b11;
    else
        Z = sum[1:0];
end

endmodule
